import React, { useEffect, useState } from 'react'
import { TreeViewRelationship } from '@fs/zion-icon'
import { ListItem } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'
import { relationshipStatusOptions } from '../useRelationshipReducer'

const hasWindow = typeof window !== 'undefined'

export default function ErrorStateView({ setShowStatusParams, dispatchRelationshipViewingStatus }) {
  const { t } = useTranslation()
  const [showError, setShowError] = useState()

  useEffect(() => {
    setShowError(true)
  }, [])

  useEffect(() => {
    if (showError) {
      setShowStatusParams({
        message: t(
          'relation-view.get-status.error',
          'There was a problem communicating with the server. Please try again later or contact support if the problem persists.'
        ),
        actionLabel: t('contact.support', 'contact support'),
        actionCallback: () => {
          hasWindow && window.open('help/', '_blank')
        },
        type: 'error',
      })
      setShowError(false)
    }
  }, [showError, setShowStatusParams, t])

  return (
    <ListItem
      primaryText={t('relation-view.retry', 'Retry Relationship Viewing')}
      onClick={() => {
        dispatchRelationshipViewingStatus(relationshipStatusOptions.resetErrors)
      }}
      startElement={<ListItem.Icon Icon={TreeViewRelationship} />}
    />
  )
}
